import { useEffect, useCallback, useRef, useState } from 'react';

import { Boundary, Trigger, Content } from './Dropdown.styles';
import { propTypes } from './Dropdown.types';

let _uid = 0;

const getUid = () => {
  _uid++;
  return _uid.toString();
};

/**
 * A simple dropdown for toggling the visibility of content through interacting with a trigger
 */
const Dropdown = ({
  id,
  className,
  trigger,
  children,
  isOpen = false,
  disabled = false,
  onInteract,
}) => {
  const [height, setHeight] = useState('min-content');
  const [uid, setUid] = useState(getUid());

  const triggerId = `__dropdown_${uid}_trigger__`;
  const contentId = `__dropdown_${uid}_content__`;
  const contentRef = useRef(null);
  const contentEl = contentRef.current;

  /* set the uid if the id changes */
  useEffect(() => {
    id && setUid(id);
  }, [id]);

  const updateSize = useCallback(() => {
    setHeight(`${contentEl?.scrollHeight || 0}px`);
  }, [contentEl]);

  useEffect(() => {
    updateSize();
  }, [children, contentEl, updateSize]);

  useEffect(() => {
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, [updateSize]);

  const handleInteract = useCallback(
    (event) => {
      const isLink = event.target.closest('a') !== null;
      const isKey = (k) => event.key === k;

      if (
        isLink ||
        disabled ||
        !(isKey('Enter') || isKey(' ') || isKey(undefined))
      ) {
        return;
      }

      onInteract && onInteract();
    },
    [onInteract, disabled],
  );

  return (
    <Boundary id={uid} className={className}>
      {trigger && (
        <Trigger
          id={triggerId}
          role="button"
          aria-controls={contentId}
          aria-expanded={isOpen}
          aria-disabled={disabled}
          onClick={handleInteract}
          onKeyDown={handleInteract}
          tabIndex="0"
        >
          {trigger}
        </Trigger>
      )}
      {children && (
        <Content
          id={contentId}
          aria-labelledby={triggerId}
          ref={contentRef}
          $height={height}
        >
          {children}
        </Content>
      )}
    </Boundary>
  );
};

Dropdown.propTypes = propTypes;

export default Dropdown;

/**
 * A simple dropdown for toggling the visibility of content through interacting with a title
 * Only respects the isOpen prop on initial render
 */
export const DropdownStateful = ({ defaultOpen = false, ...props }) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);

  const onInteract = () => setIsOpen((isOpen) => !isOpen);

  return <Dropdown {...props} isOpen={isOpen} onInteract={onInteract} />;
};

DropdownStateful.propTypes = propTypes;
