import { PropTypes } from 'prop-types';

export const propTypes = {
  /** Custom classname for the dropdown */
  className: PropTypes.string,
  /** Unique identifier for the dropdown */
  id: PropTypes.string,
  /** The trigger of the dropdown */
  trigger: PropTypes.oneOfType([PropTypes.string, PropTypes.node]).isRequired,
  /** The content which is hidden by the dropdown */
  children: PropTypes.node.isRequired,
  /** Whether the dropdown is open or not */
  isOpen: PropTypes.bool,
  /** Whether the dropdown is disabled or not */
  disabled: PropTypes.bool,
  /** Function to be called when the dropdown is interacted with */
  onInteract: PropTypes.func,
};
